+    fn formatted_prefix(
+        self,
+        value: u64,
+        alt_form: bool,
+        first_digit_is_zero: bool,
+    ) -> &'static [u8] {
+        if !alt_form || value == 0 {
+            return b"";
+        }
+        match self {
+            Self::Octal if first_digit_is_zero => b"",
+            _ => self.alt_prefix(),
+        }
+    }
+
+    fn preserves_single_zero_when_suppressed(self, alt_form: bool) -> bool {
+        alt_form && matches!(self, Self::Octal)
+    }
 }

